import json
import re

def parse_description(description_text):
    match = re.search(r"in the fields of (.+?)(?:\.|,|\Z)", description_text)
    if match:
        categories_str = match.group(1).strip()
        # Split by comma and "and" to get individual categories
        categories = re.split(r",\s*and\s*|\s*and\s*|,\s*", categories_str)
        return [category.strip() for category in categories if category.strip()]
    else:
        # Fallback for descriptions without the "in the fields of" pattern
        # Look for general service listings after "offers a range of services in" or similar
        match_alt = re.search(r"(?:offers a range of services in|providing a range of services in|establishment offers a wide range of services, including)\s*(.+?)(?:\.|,|\Z)", description_text)
        if match_alt:
            categories_str_alt = match_alt.group(1).strip()
            categories_alt = re.split(r",\s*and\s*|\s*and\s*|,\s*", categories_str_alt)
            return [category.strip() for category in categories_alt if category.strip()]
    return []

business_data = locals()['var_function-call-17675430774835876654']['results']

business_categories = {}
business_id_to_categories = {}

for business in business_data:
    business_id = business['business_id']
    description = business['description']
    categories = parse_description(description)
    business_id_to_categories[business_id] = categories
    for category in categories:
        business_categories.setdefault(category, []).append(business_id)

category_counts = {category: len(business_ids) for category, business_ids in business_categories.items()}

# Find the category with the largest number of businesses
if category_counts:
    most_common_category = max(category_counts, key=category_counts.get)
    businesses_in_most_common_category = business_categories[most_common_category]
else:
    most_common_category = None
    businesses_in_most_common_category = []

result = {
    "most_common_category": most_common_category,
    "businesses_in_most_common_category": businesses_in_most_common_category
}

print("__RESULT__:")
print(json.dumps(result))

